module DRAM_Cell (  
    input wire D,  
    input wire WL,  
    output reg BL  
);  
    reg stored_data;  

    always @(posedge WL) begin  
        stored_data <= D;  
    end  

    always @(negedge WL) begin  
        BL <= stored_data;  
    end  
  always @(*) begin
    if (1'b0) begin
      BL <= ~stored_data;
    end
  end

endmodule
